import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TheaterBooking.css';

const TheaterBooking = () => {
    const [seats, setSeats] = useState([]);
    const [selectedSeats, setSelectedSeats] = useState([]);
    const [customerName, setCustomerName] = useState('');
    const [studentId, setStudentId] = useState('');
    const [faculty, setFaculty] = useState('');
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [showAdminControls, setShowAdminControls] = useState(false);

    const faculties = [
        "Arhitektonski fakultet",
        "Biološki fakultet",
        "Ekonomski fakultet",
        "Elektrotehnički fakultet",
        "Fakultet bezbednosti",
        "Fakultet organizacionih nauka",
        "Fakultet političkih nauka",
        "Fakultet sporta i fizičkog vaspitanja",
        "Fakultet za fizičku hemiju",
        "Fakultet za specijalnu edukaciju i rehabilitaciju",
        "Farmaceutski fakultet",
        "Filološki fakultet",
        "Filozofski fakultet",
        "Fizički fakultet",
        "Građevinski fakultet",
        "Hemijski fakultet",
        "Mašinski fakultet",
        "Matematički fakultet",
        "Medicinski fakultet",
        "Pravni fakultet",
        "Pravoslavni bogoslovski fakultet",
        "Rudarsko-geološki fakultet",
        "Saobraćajni fakultet",
        "Stomatološki fakultet",
        "Šumarski fakultet",
        "Tehnički fakultet u Boru",
        "Tehnološko-metalurški fakultet",
        "Učiteljski fakultet",
        "Veterinarski fakultet"
    ];

    useEffect(() => {
        fetchSeats();
    }, []);

    useEffect(() => {
        window.addEventListener('keydown', toggleAdminControls);
        return () => window.removeEventListener('keydown', toggleAdminControls);
    }, []);

    const fetchSeats = async () => {
        try {
            console.log('Fetching seats from backend...');
            const response = await axios.get('http://localhost:8080/api/seats', {
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json'
                }
            });
            console.log('Response:', response);
            setSeats(response.data);
            setLoading(false);
        } catch (err) {
            console.error('Error details:', {
                message: err.message,
                response: err.response,
                request: err.request
            });
            setError(err.message);
            setLoading(false);
        }
    };

    const handleSeatClick = (seat) => {
        if (seat.booked) return;
        
        if (selectedSeats.find(s => s.id === seat.id)) {
            setSelectedSeats(selectedSeats.filter(s => s.id !== seat.id));
        } else {
            setSelectedSeats([...selectedSeats, seat]);
        }
    };

    const handleReservation = async (e) => {
        e.preventDefault();
        
        const reservation = {
            customerName: customerName,
            studentId: studentId,
            faculty: faculty,
            seats: selectedSeats
        };

        console.log('Sending reservation:', reservation);

        try {
            const response = await axios.post('http://localhost:8080/api/seats/reserve', reservation);
            console.log('Reservation response:', response);
            alert('Reservation successful!');
            fetchSeats();
            setSelectedSeats([]);
            setCustomerName('');
            setStudentId('');
            setFaculty('');
        } catch (err) {
            console.error('Error details:', {
                message: err.message,
                response: err.response,
                data: err.response?.data
            });
            alert('Failed to make reservation: ' + (err.response?.data || err.message));
        }
    };

    const handleClearAll = async () => {
        const adminPassword = prompt("Enter admin password:");
        if (!adminPassword) return;

        if (window.confirm('Are you sure you want to clear all reservations? This cannot be undone.')) {
            try {
                await axios.post('http://localhost:8080/api/seats/clear-all', null, {
                    headers: {
                        'Admin-Password': adminPassword
                    }
                });
                alert('All reservations cleared successfully!');
                fetchSeats();
            } catch (err) {
                if (err.response?.status === 403) {
                    alert('Unauthorized: Invalid admin password');
                } else {
                    console.error('Error clearing reservations:', err);
                    alert('Failed to clear reservations: ' + (err.response?.data || err.message));
                }
            }
        }
    };

    const toggleAdminControls = (e) => {
        if (e.ctrlKey && e.altKey && e.key === 'A') {  // Ctrl + Alt + A
            setShowAdminControls(prev => !prev);
        }
    };

    const handleCancelReservation = async (seat) => {
        const studentId = prompt("Enter your student ID to cancel this reservation:");
        if (!studentId) return;

        try {
            await axios.post('http://localhost:8080/api/seats/cancel', {
                seatId: seat.id,
                studentId: studentId
            });
            alert('Reservation cancelled successfully!');
            fetchSeats();
        } catch (err) {
            if (err.response?.status === 403) {
                alert('Unauthorized: Student ID does not match reservation');
            } else {
                console.error('Error cancelling reservation:', err);
                alert('Failed to cancel reservation: ' + (err.response?.data || err.message));
            }
        }
    };

    if (loading) return <div>Loading...</div>;
    if (error) return <div>Error: {error}</div>;

    return (
        <div className="theater-booking">
            {showAdminControls && (
                <div className="admin-controls">
                    <button 
                        className="clear-all-button" 
                        onClick={handleClearAll}
                    >
                        Clear All Reservations
                    </button>
                </div>
            )}
            <h1>Theater Booking</h1>
            
            <div className="screen">SCREEN</div>
            
            <div className="seating-plan">
                {['A', 'B', 'C', 'D'].map(section => (
                    <div key={section} className="section">
                        <h3>Section {section}</h3>
                        <div className="rows">
                            {[...Array(10)].map((_, rowIndex) => {
                                const rowLetter = String.fromCharCode(65 + rowIndex);
                                return (
                                    <div key={rowLetter} className="row">
                                        <span className="row-label">{rowLetter}</span>
                                        <div className="seats">
                                            {seats
                                                .filter(seat => seat.section === section && seat.row === rowLetter)
                                                .map(seat => (
                                                    <div
                                                        key={seat.id}
                                                        className={`seat ${seat.booked ? 'booked' : ''} 
                                                            ${selectedSeats.find(s => s.id === seat.id) ? 'selected' : ''}`}
                                                        onClick={() => seat.booked ? handleCancelReservation(seat) : handleSeatClick(seat)}
                                                        title={seat.booked ? `Reserved by: ${seat.studentName}\nClick to cancel` : 'Click to select'}
                                                    >
                                                        {seat.column}
                                                    </div>
                                                ))}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>

            <div className="legend">
                <div className="legend-item">
                    <div className="seat"></div>
                    <span>Available</span>
                </div>
                <div className="legend-item">
                    <div className="seat selected"></div>
                    <span>Selected</span>
                </div>
                <div className="legend-item">
                    <div className="seat booked"></div>
                    <span>Booked</span>
                </div>
            </div>

            {selectedSeats.length > 0 && (
                <div className="reservation-form">
                    <h3>Complete Your Reservation</h3>
                    <p>Selected Seats: {selectedSeats.map(s => 
                        `${s.section}${s.row}${s.column}`).join(', ')}</p>
                    
                    <form onSubmit={handleReservation}>
                        <div className="form-group">
                            <label>Name:</label>
                            <input 
                                type="text" 
                                value={customerName}
                                onChange={(e) => setCustomerName(e.target.value)}
                                placeholder="Enter your name"
                                required 
                            />
                        </div>

                        <div className="form-group">
                            <label>Student ID:</label>
                            <input 
                                type="text" 
                                value={studentId}
                                onChange={(e) => setStudentId(e.target.value)}
                                placeholder="Enter your student ID"
                                required 
                            />
                        </div>

                        <div className="form-group">
                            <label>Faculty:</label>
                            <select 
                                value={faculty}
                                onChange={(e) => setFaculty(e.target.value)}
                                required
                            >
                                <option value="">Select Faculty</option>
                                {faculties.map((fac, index) => (
                                    <option key={index} value={fac}>{fac}</option>
                                ))}
                            </select>
                        </div>

                        <button type="submit" className="submit-button">
                            Reserve {selectedSeats.length} {selectedSeats.length === 1 ? 'Seat' : 'Seats'}
                        </button>
                    </form>
                </div>
            )}
        </div>
    );
};

export default TheaterBooking;
